    const g = new THREE.Group(); const hide = mat(color); const dark = mat(shade(color, 0.72)); const stud = metalMat(0xc9cdd3); /* studded leather body */ const body = new THREE.Mesh(new THREE.SphereGeometry(0.258, 14, 12), hide); body.scale.set(1.0, 0.66, 0.8); body.position.set(0, 0.06, 0.03); g.add(body); /* rows of metal studs across the chest dome */ for (let r = 0; r < 3; r++) { const ry = 0.18 - r * 0.13; const cnt = 4; for (let i = 0; i < cnt; i++) { const a = (i - (cnt - 1) / 2) * 0.5; const s = new THREE.Mesh(new THREE.SphereGeometry(0.014, 6, 5), stud); s.position.set(Math.sin(a) * 0.19, ry, Math.cos(a) * 0.19 + 0.02); g.add(s); } } /* studded shoulder caps */ for (const s of [-1, 1]) { const pad = new THREE.Mesh(new THREE.SphereGeometry(0.11, 10, 8), dark); pad.scale.set(1, 0.6, 1); pad.position.set(0.29 * s, 0.21, 0); g.add(pad); for (let i = 0; i < 3; i++) { const st = new THREE.Mesh(new THREE.SphereGeometry(0.013, 6, 5), stud); st.position.set(0.29 * s + (i - 1) * 0.05, 0.25, 0.05); g.add(st); } } /* studded belt */ const belt = new THREE.Mesh(new THREE.TorusGeometry(0.235, 0.03, 6, 18), dark); belt.rotation.x = Math.PI / 2; belt.position.y = -0.26; belt.scale.set(1, 1, 0.85); g.add(belt); for (let i = 0; i < 6; i++) { const a = (i / 6) * Math.PI - Math.PI / 2; const st = new THREE.Mesh(new THREE.SphereGeometry(0.013, 6, 5), stud); st.position.set(Math.sin(a) * 0.235, -0.26, Math.cos(a) * 0.2 + 0.02); g.add(st); } return g;
